var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"오, 오오......!","JPN":"お、おお……！","ENG":"Oh... Ooh!","TWN":"噢，噢噢……！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"좌표도, 침식파 농도도...... 교수님의 연구 자료에 나왔던 것과 완벽하게 일치해......!","JPN":"座標も、侵食波濃度も……教授の研究資料と完全一致している……！","ENG":"The coordinates and the Corruption Ray saturation... They all match the professor's research notes perfectly!","TWN":"無論是座標還是侵蝕波濃度……都跟教授研究的資料完美一致……！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"틀림없습니다! 여기가 바로 그 유적으로 통하는 길이에요!","JPN":"間違いありません！　ここが遺跡に通じる道です！","ENG":"This must be it! We're on the path toward the ruins!","TWN":"沒錯了！這裡就是通往遺跡的道路！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"리타 언니, 저희가 제대로 도착한 걸까요?","JPN":"リタお姉ちゃん、本当にここが目的地なんでしょうか？","ENG":"Do you think we're at the right spot, Rita?","TWN":"麗塔姐姐，我們到達目的地了嗎？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"맞겠지. 윌버 녀석이 목이 터져라 웃고 있잖아.","JPN":"合ってるんじゃないか。ウィルバーの奴があんなデカい声で笑ってるし。","ENG":"Probably. Wilbur's laughing his face off.","TWN":"應該是吧，看韋爾伯那傢伙笑得嗓子都啞了。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"담배 피우느라 건성으로 대답하지 말고요.","JPN":"タバコを吸いながら適当に答えるのはやめてください。","ENG":"Come on, put out that smoke and answer me properly.","TWN":"別只顧抽煙，就隨便敷衍我。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"이상하잖아요. 유적이라고 할 만한 건 아무리 주위를 살펴 봐도 없는걸요.","JPN":"おかしいと思いませんか。遺跡らしきものは周りに一つもないのに。","ENG":"Don't you think it's weird? There's nothing in the area that looks like ruins.","TWN":"不覺得奇怪嗎。這周圍不管怎麼看都沒有跟遺跡沾上邊的東西呀。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"너도 어렴풋이 알고 있었잖아. 망상으로 끝날 거라는 걸.","JPN":"お前も薄々わかってんじゃないか。結局妄想で終わるってことを。","ENG":"You saw it coming too, didn't you? This trip is going to end up bursting his bubble.","TWN":"你也應該有所察覺了吧。一切只不過是他的幻想罷了。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"들것이나 준비해 둬. 현실을 깨닫고 나면 졸도할 테니까.","JPN":"担架でも用意しておけ。あいつが現実を突きつけられて卒倒するかもしれないから。","ENG":"Get a stretcher ready. He's going to pass out the moment he realizes he's been duped.","TWN":"還是準備擔架吧。他認清到現實後就會暈過去的。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"그렇게 원하던 곳에 기어코 와 버렸군, 윌버.","JPN":"ついに夢見た場所に来てしまったな、ウィルバー。","ENG":"So you really made it after all, Wilbur.","TWN":"你終於來到了夢寐以求的地方，韋爾伯。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"그렇습니다. 정말 감격스러운 순간이에요.","JPN":"はい。本当に感激の瞬間です。","ENG":"Indeed. Words cannot describe how my heart swells at this moment.","TWN":"是啊，真是感慨萬千啊。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"이제 곧 유적으로 통하는 입구가 열리겠죠? 가슴이 두근거려 미치겠어요!","JPN":"もうすぐ遺跡に繋がる入口が開くでしょう。胸が高鳴り狂ってしまいそうです！","ENG":"The entrance to the ruins should open up soon. I feel like my heart is going to explode!","TWN":"通往遺跡的入口馬上就要打開了吧？我激動得快發瘋了。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"두 눈 똑바로 뜨고 잘 봐. 유적은 없어.","JPN":"両目をしっかり開けて見ろ。遺跡はない。","ENG":"Look all you want. There are no ruins.","TWN":"睜開你的雙眼好好看看，這裡沒有遺跡。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L21_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"피크닉은 끝이야. 프론트 베이로 떠나기 전에 마음의 준비나 해 둬.","JPN":"ピクニックはおしまいだ。フロントベイに行く心の準備でもしておけ。","ENG":"The picnic's over. You might as well as prepare yourself mentally before you head to Front Bay.","TWN":"郊遊結束了，做好去前灣的心理準備吧。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L22_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"후......","JPN":"ふ……","ENG":"Hah...","TWN":"呵……"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"후훗...... 후후후후......!","JPN":"ふふふ……ふふふっ……！","ENG":"Hah hah... Bwa hah hah!","TWN":"嘻嘻……嘻嘻嘻嘻哈……！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"왜 웃지? 충격 때문에 정신이 나가기라도 했나?","JPN":"なぜ笑う？　衝撃のせいで頭がおかしくなってしまったのか？","ENG":"Why are you laughing? Have you lost your mind from the shock?","TWN":"笑什麼？難道是打擊太大所以精神錯亂了？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"아뇨, 아닙니다. 이래서 사람은 배워야 한다는 거구나 싶어서요.","JPN":"いいえ、違います。だから人間は学ばなければならないと改めて思っただけです。","ENG":"Oh, on the contrary. I'm just amused by your ignorance.","TWN":"不、不是的。我就說過了~人應該要不斷學習。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"아직도 모르겠어요? 이면세계는 현실의 법칙에 얽매이지 않는단 말입니다!","JPN":"まだ気付いていませんか？　裏世界は現実の法則に縛られないということを！","ENG":"Don't you see? The Counterside is not bound by our laws of nature!","TWN":"你還不知道嗎？異界是不受現實規則約束的！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"이제 그만 인정할 때야. 그런다고 없던 유적이 나타나진 않아.","JPN":"いい加減諦めろ。そんなことを言ったところで無かった遺跡が現れることはない。","ENG":"It's about time you come to terms with reality. Your ruins won't just pop out of thin air just because you're in denial.","TWN":"你也該面對現實了，再怎麼樣遺跡也不會憑空出現。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"저, 리타 언니......","JPN":"あのお、リタお姉ちゃん……","ENG":"Um... Rita?","TWN":"那個，麗塔姐姐……"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"그럼 저건...... 뭐예요?","JPN":"あれは……なんですか？","ENG":"Then what... is that?","TWN":"那個……是什麼？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"......유적?","JPN":"……遺跡？","ENG":"The ruins?","TWN":"……遺跡？"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"PMC_NPC_TYPEB_NULL","text":{"KOREA":"가, 갑자기 건물이 안개 속에서 나타났어!","JPN":"きゅ、急に霧の中から建物が現れた！","ENG":"A building just popped out of the fog!","TWN":"建、建築突然出現在煙霧中！"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_NPC_TYPEB_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L38_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"바로 저겁니다! 제가 그토록 찾던 유적이! 이렇게 저를 맞이해 주지 않습니까!","JPN":"まさにそれです！　僕が長年探していた遺跡が！　こうして僕を迎えてくれたのです！","ENG":"That's it! That's the ruin I've been searching for so dearly! It's here to greet me!","TWN":"就是那個！我千辛萬苦尋找的遺跡！你看它在向我招手！"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_NPC_TYPEB_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"그토록 고대하던 날이......! 그동안 받아 온 조롱과 무시를 모조리 되갚아 줄 때가 온 겁니다!","JPN":"あれほど待ちに待った日が……！　今まで受けてきた嘲笑や侮辱をすべて返す時が来ました！","ENG":"The day I've longed for has finally arrived! It's time I showed everyone who mocked me they were wrong!","TWN":"我盼望已久的……！之前受到的嘲弄和無視，終於可以如數還給那些傢伙的時候終於到了！"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_NPC_TYPEB_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"우와아......","JPN":"うわあ……","ENG":"Whoa...","TWN":"哇啊……"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"흥. 겨우 건물 하나 나타난 거 가지고 호들갑은.","JPN":"ふん、たかが建物が一つ現れただけで大げさだな。","ENG":"Hmpf. It's just a building. Big whoop.","TWN":"哼，只不過出現一個建築而已，驚呼什麼。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"자, 구경은 유적에 도착한 뒤에 얼마든지 하세요! 다들 어서 갑시다!","JPN":"さあ、見物は遺跡に到着してから思う存分してください！　早く行きましょう！","ENG":"Save the sightseeing till we get there! Let's hurry!","TWN":"好了，等一下到了遺跡後可以盡情參觀！大家快走吧！"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"들뜬 와중에 미안하지만 무작정 갔다간 무사하지 못할 겁니다, 휴먼.","JPN":"浮かれているところすみませんが、むやみに入って無事に帰れるという保証はありません、ヒューマン。","ENG":"I hate to be a wet blanket, but you'll be sorry if you just barge in there, human.","TWN":"不好意思打擾一下，這樣盲目地進去有些不妥，人類。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"유적이 출몰한 순간부터 침식파 반응이 급증하고 있습니다. 침식체들에게 넝마가 되기 싫다면 신중하게 움직여야 합니다.","JPN":"遺跡が出没した瞬間から侵食波反応が急増しています。侵食体の餌食になりたくなければ慎重に動かなければなりません。","ENG":"Corruption Ray levels spiked the moment that building appeared. We should move with due caution if you don't want C.O.s to tear you apart.","TWN":"從遺跡出現的那一刻開始，侵蝕波反應就急劇增加。如果不想被侵蝕體撕成碎片，最好謹慎行動。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"침식체 따위가 무슨 대수라고! 길이 닫히기 전에 어서 다녀와야 합니다!","JPN":"侵食体なんて大したことない！　道が閉ざされる前に早く行かないと！","ENG":"Who cares about some dumb C.O.s? We have to get in there before the path closes!","TWN":"侵蝕體算什麼！我們必須在通道關閉之前快去快回！"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"꼬맹이, 넌 수송선에 남아 있어.","JPN":"ガキ、お前は輸送船に残ってろ。","ENG":"Stay in the ship, kid.","TWN":"小鬼，你留在運輸船裡。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"네? 저도 안에 들어가 보고 싶은데요?","JPN":"え？　私も中に入りたいのに！","ENG":"What? But I want to check it out too!","TWN":"嗯？我也想進去看看。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"넌 예외야. 위험한 현장에 굳이 머리를 들이밀 필요 없어.","JPN":"お前は例外だ。危険な現場にあえて首を突っ込む必要はない。","ENG":"You can't. There's no reason to put you at risk.","TWN":"你不行，你沒必要去那種危險的地方。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"그렇지만 리타 언니랑 같이 있는 게 더 안전한 걸요.","JPN":"でもリタお姉ちゃんと一緒にいたほうが安全ですよ。","ENG":"But I'll be safer with you.","TWN":"但是跟麗塔姐姐在一起可能更安全呢。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"저도 같이 갈게요, 네? 네에?","JPN":"私も一緒に行きたいです。いいですよね？　ね？","ENG":"Can I please come? Pretty please?","TWN":"我也一起去吧，好不好？好不好嘛？"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"......이 놈이나 저 놈이나 자기 하고 싶은 대로만 하지.","JPN":"……どいつもこいつも好き勝手しやがって。","ENG":"Nobody ever listens to me, do they?","TWN":"……你們一個個都這樣，真是太亂來了。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L8_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"죽고 싶으면 마음대로 해. 망할 꼬맹이.","JPN":"死にたいなら好きにしろ、くそガキ。","ENG":"Suit yourself, if you'd rather die. You good-for-nothing kid.","TWN":"想死的話就隨便吧，臭小鬼。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"앗! 리타 언니! 같이 가요!","JPN":"あっ！　リタお姉ちゃん！　一緒に行きましょう！","ENG":"Oh! Rita! Wait for me!","TWN":"啊！麗塔姐姐！一起走嘛！"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};